        long originalProfit = 0;
        for (int i = 0; i < n; i++) {
            originalProfit += strategy[i] * prices[i];
        }
        maxProfit = originalProfit;

        // Try all possible k-length consecutive subarrays to modify
        for (int i = 0; i <= n - k; i++) {
            // Create a copy of the strategy array
            long[] modifiedStrategy = Arrays.copyOf(strategy, n);

            // Modify the subarray from i to i + k - 1
            for (int j = 0; j < k; j++) {
                modifiedStrategy[i + j] = 0; // Hold for first k/2 days
            }
            for (int j = k / 2; j < k; j++) {
                modifiedStrategy[i + j] = 1; // Sell for last k/2 days
            }

            // Calculate the profit with the modified strategy
            long currentProfit = 0;
            for (int j = 0; j < n; j++) {
                currentProfit += modifiedStrategy[j] * prices[j];
            }

            // Update maxProfit if currentProfit is higher
            maxProfit = Math.max(maxProfit, currentProfit);
        }

        return maxProfit;
    }
}
