import java.util.*;

public class Solution {
    public static long solve(long[] prices, long[] strategy, long k) {
        long maxProfit = 0;
        int n = prices.length;

        // Calculate the original profit
        for (int i = 0; i < n; i++) {
            maxProfit += strategy[i] * prices[i];
        }

        // Try all possible windows of size k
        for (int i = 0; i <= n - k; i++) {
            // Calculate the profit change if we modify the window [i, i + k - 1]
            long delta = 0;

            // Original strategy in the window
            long originalBuy = 0;
            long originalSell = 0;

            // New strategy in the window: first k/2 elements are 0 (hold), next k/2 are 1 (sell)
            long newBuy = 0;
            long newSell = 0;

            for (int j = 0; j < k; j++) {
                if (strategy[i + j] == -1) {
                    originalBuy++;
                } else if (strategy[i + j] == 1) {
                    originalSell++;
                }
            }

            // Calculate the original contribution of the window
            long originalContribution = originalBuy * (-prices[i]) + originalSell * prices[i + k - 1];

            // Calculate the new contribution of the window
            long newContribution = newBuy * (-prices[i]) + newSell * prices[i + k - 1];

            // Calculate the delta
            delta = newContribution - originalContribution;

            // Update maxProfit if this window gives a better profit
            if (delta > 0) {
                maxProfit += delta;
            }
        }

        return maxProfit;
    }
}
